<template>
	<view class="">
		<u-navbar title="选择商品" :z-index="980" :custom-back="$util.back">
			<template #right>
				<view class="navbar-right">
					<view class="btn-item" @click="handelFilterClick">
						<u-icon name="search"></u-icon>
						<text>筛选</text>
					</view>
					<view class="btn-item" @click="handelManagerClick">
						<u-icon name="list-dot"></u-icon>
						<text v-if="isManage">取消</text>
						<text v-else>管理</text>
					</view>
				</view>
			</template>
		</u-navbar>
		<scroll-view @touchmove.stop :scroll-y="true" class="scroll_content" :rebound="false"
			:style="{height:scrollHeight+'px'}" @scrolltolower="lower">
			<card-group-goods-list :list="list" :selectedIds="selectedIds" :isManage="isManage"
				@selected-ids="handelSelectedIdsChange">
				<template #opts="{row}">
					<view class="btn bg-blue" @click="handelChoose(row)">选择</view>
				</template>
			</card-group-goods-list>
			<u-loadmore :status="loading" icon-type="circle" @loadmore="fetchData" />
		</scroll-view>
		<view class="footer" v-if="isManage">
			<view class="wrap">
				<view class="checker" :class="{'checker-on':isSelectAll}" @click="handelAllSelected">
					<u-icon name="checkmark-circle" size="30"></u-icon>
				</view>
				<view class="btns">
					<view class="btn-item bg-blue" @click="handelChoose()">确定</view>
				</view>
			</view>
		</view>
		<card-group-goods-filter ref="card-group-goods-filter" @ok="handelFilterChange" />
	</view>
</template>

<script>
	import CardGroupGoodsList from './components/card-group-goods-list'
	import CardGroupGoodsFilter from './components/card-group-goods-filter'
	export default {
		components: {
			'card-group-goods-list': CardGroupGoodsList,
			'card-group-goods-filter': CardGroupGoodsFilter,
		},
		data() {
			return {
				scrollHeight: 0,

				queryForm: {
					page: 1,
					limit: 20,
					goods_id: '',
					goods_name: '',
					category_ids: [], //分类ID数组
					goods_type: '',
					set_type: '', //0默认 1=已设置 2=未设置
					batch_id: '', //卡组ID
				},

				list: [], //卡组列表
				total: 0,
				loading: 'loadmore',

				isManage: false,
				isSelectAll: false,
				selectedIds: [],
			};
		},
		onReady() {
			this.$nextTick(() => {
				uni.createSelectorQuery().select(".scroll_content").boundingClientRect(res => {
					this.scrollHeight = this.deviceInfo.screenHeight - res.top
				}).exec()
			})
		},
		onLoad(e) {
			const {
				id
			} = e
			if (id) {
				this.queryForm.batch_id = id
				this.queryForm.set_type = 2
			}
			this.fetchData()
		},
		onHide() {
			// this.queryForm = this.$options.data().queryForm
			this.isManage = false
		},
		methods: {
			async fetchData() {
				if (this.loading == 'nomore')
					return
				this.loading = 'loading'
				const {
					list,
					total,
					url
				} = await this.$u.api.getCardBatchGoods(this.queryForm)
				this.total = total
				this.url = url
				if (list.length) {
					this.list = this.list.concat(list)
				}
				if (list.length < this.queryForm.limit) {
					this.loading = 'nomore'
				} else {
					this.loading = 'loadmore'
				}
			},
			reloadData() {
				this.queryForm.page = 1
				this.loading = 'loadmore'
				this.list = []
				this.fetchData()
			},
			// 加载下一页
			lower() {
				if (this.loading == 'nomore')
					return
				this.queryForm.page++
				this.fetchData()
			},
			// 筛选点击
			handelFilterClick() {
				this.$refs['card-group-goods-filter'].showEdit(this.queryForm)
			},
			// 筛选回调
			handelFilterChange(e) {
				this.queryForm = Object.assign({}, e)
				this.reloadData()
			},
			// 管理点击
			handelManagerClick() {
				if (!this.list.length) {
					this.$util.msg('列表数据为空')
					return
				}
				this.isManage = !this.isManage
				this.isSelectAll = false
				this.selectedIds = []
			},
			// 全选
			handelAllSelected() {
				this.isSelectAll = !this.isSelectAll
				if (this.isSelectAll) {
					let ids = []
					this.list.map(item => {
						ids.push(item.id)
					})
					this.selectedIds = ids
				} else {
					this.selectedIds = []
				}
			},
			// 选中改变回调
			handelSelectedIdsChange({
				selectedIds,
				isSelectAll
			}) {
				this.selectedIds = selectedIds
				this.isSelectAll = isSelectAll
			},
			// 确定点击
			handelChoose(row) {
				let arr = []
				if (row) {
					arr.push(row)
				} else {
					if (!this.selectedIds.length) {
						this.$util.msg('未选择数据')
						return
					}
					this.list.forEach(item => {
						if (this.selectedIds.includes(item.id))
							arr.push(item)
					})
				}
				const pages = getCurrentPages()
				if (pages.length > 1) {
					uni.navigateBack({
						delta: 1, // 返回上一级页面
						success: function() {
							const prevPage = pages[pages.length - 2]; // 上一页面对象
							// 在上一页面中接收参数
							prevPage.setGoodsData({
								receivedParams: arr // 这里的 receivedParams 是上一页面的数据变量名
							});
						}
					})
				} else {
					this.$util.on('/pages/index/index')
				}
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.checker {
		padding-right: 20rpx;
		color: #B0B0B0 !important;
	}

	.checker-on {
		color: #F05C02 !important;
	}

	.navbar-right {
		margin-right: 18rpx;
		display: flex;
		gap: 20rpx;

		.btn-item {}

		.btn-item:active {
			opacity: .6;
		}
	}

	.footer {
		position: fixed;
		bottom: 0;
		z-index: 11;
		width: 100%;
		height: 104rpx;
		background-color: #fff;
		border-top: 1px solid #ccc;
		flex-wrap: nowrap;
		justify-content: space-between;
		align-items: center;
		display: flex;
		padding: 20rpx;

		.wrap {
			width: 100%;
			display: flex;
			align-items: center;

			.checker {}

			.btns {
				flex: 1;
				display: flex;
				gap: 10rpx;
				justify-content: flex-end;

				.btn-item {
					white-space: nowrap;
					border-radius: 20rpx;
					padding: 2rpx 20rpx;
					color: #fff;
					display: block;
					text-align: center;
					width: 100rpx;
				}

				.btn-item:active {
					opacity: .6;
				}
			}
		}
	}
</style>